import React from "react"
import LinkedInIcon from "@material-ui/icons/LinkedIn"
import { withStyles, Link, Typography, Box } from "@material-ui/core"
import GithubIcon from "./Icons/github"
import BehanceIcon from "./Icons/behance"
import BseIcon from "./Icons/bse"

const SocialLinkBase = withStyles(theme => {
  return {
    root: {
      display: "inline-flex",
      alignItems: "center",
      color: "#bab8b4",
      transition: "color 0.1s",
      "&:hover": {
        color: "#9f9a9c",
      },
      marginLeft: "1rem",
      marginRight: "1rem",
      "& > svg": {
        marginRight: "0.5rem",
      },
      // justifyContent: 'center',
      // background:'red',
    },
  }
})(Link)

const SocialLink = ({ Icon, children, ...props }) => {
  return (
    <SocialLinkBase
      underline="none"
      target="_blank"
      rel="noopener"
      alt={children}
      {...props}
    >
      <Icon />
      <Typography variant="overline">{children}</Typography>
    </SocialLinkBase>
  )
}

const SocialBlock = () => {
  return (
    <Box textAlign="center">
      <SocialLink
        href="https://www.linkedin.com/in/%E7%A6%AE%E5%AE%89-%E9%8D%BE-439144193/"
        Icon={LinkedInIcon}
        title="Chung, LiAn on LinkedIn"
      >
        LinkedIn
      </SocialLink>
      <SocialLink
        href="https://github.com/hikariNTU"
        Icon={GithubIcon}
        title="HikariNTU personal Github page"
      >
        Github
      </SocialLink>
      <SocialLink
        href="https://www.behance.net/NTUhikari"
        Icon={BehanceIcon}
        title="NTUHikari on Behance, a place to show your art"
      >
        Behance
      </SocialLink>
      <SocialLink
        href="https://blender.stackexchange.com/users/73532/hikaritw"
        Icon={BseIcon}
        title="HikariTW on Blender Stack Exchange"
      >
        Blender SE
      </SocialLink>
    </Box>
  )
}

export default SocialBlock
